/* --- Runtime helpers (inline C for STM32G431KB) --- */

static inline float iwt_interpolate_linear(
    const int16_t* table, int32_t idx, float frac) {
    float a = (float)table[idx];
    float b = (float)table[idx + 1];
    return a + (b - a) * frac;
}

static inline float iwt_interpolate_hermite(
    const int16_t* table, int32_t idx, float frac) {
    float xm1 = (float)table[idx];
    float x0  = (float)table[idx + 1];
    float x1  = (float)table[idx + 2];
    float x2  = (float)table[idx + 3];
    float c = (x1 - xm1) * 0.5f;
    float v = x0 - x1;
    float w = c + v;
    float a = w + v + (x2 - x0) * 0.5f;
    float b_neg = w + a;
    return (((a * frac) - b_neg) * frac + c) * frac + x0;
}

typedef struct {
    float previous;
    float lp;
} iwt_differentiator_t;

static inline void iwt_diff_init(iwt_differentiator_t* d) {
    d->previous = 0.0f;
    d->lp = 0.0f;
}

static inline float iwt_diff_process(
    iwt_differentiator_t* d, float coeff, float s) {
    float delta = s - d->previous;
    d->lp += coeff * (delta - d->lp);  /* one-pole LP */
    d->previous = s;
    return d->lp;
}

